const b = $input.item.json.body || {};
const d = b.data || b;

const wa = (d.key?.remoteJid || b.sender?.jid || '5511999999999').split('@')[0].trim();
const name = (d.pushName || b.sender?.name || 'Cliente').trim();
const msg = (d.message?.conversation || b.message?.conversation || d.message?.extendedTextMessage?.text || b.message?.extendedTextMessage?.text || '').trim();

if (!msg) {
  throw new Error('Mensagem vazia ou formato não suportado');
}

return { json: { whatsapp: wa, nome_cliente: name, conversa: msg } };

const queryResult = $input.all();
const incoming = $node["Limpar Dados"].json;

let lead = null;
let exists = false;

if (queryResult.length > 0 && queryResult[0].json && queryResult[0].json.id) {
  lead = queryResult[0].json;
  exists = true;
}

let prompt = "";
if (exists) {
  prompt = `Este cliente já tem histórico.\nNome: "${lead.nome_cliente}"\nResumo anterior: "${lead.resumo_ia || 'Nenhum'}"\nFase: "${lead.status_funil}"\n\nNova mensagem do cliente:\n"${incoming.conversa}"\n\nAnalise considerando o histórico. Atualize o resumo.`;
} else {
  prompt = `Primeiro contato deste cliente.\nMensagem:\n"${incoming.conversa}"\n\nAnalise e extraia os dados para qualificar o lead.`;
}

return {
  json: {
    prompt,
    exists,
    lead_id: exists ? lead.id : null,
    whatsapp: incoming.whatsapp,
    nome_cliente: incoming.nome_cliente,
    conversa: incoming.conversa
  }
};

const jsonInput = $input.item.json;
let raw = jsonInput.output || jsonInput.text;
if (!raw && jsonInput.message) raw = jsonInput.message.content;
if (!raw) throw new Error('Resposta vazia da IA');

raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
const d = JSON.parse(raw);

const mergeNode = $node["Merge Context"].json;

const payload = {
  whatsapp: mergeNode.whatsapp,
  nome_cliente: d.nome_cliente || mergeNode.nome_cliente || 'Cliente WhatsApp',
  tipo_servico: d.tipo_servico || null,
  material: d.material || null,
  medidas_brutas: d.medidas_brutas || null,
  cor_acabamento: d.cor_acabamento || null,
  resumo_ia: d.resumo_ia || null,
  proxima_acao: d.proxima_acao || null,
  temperatura_lead: d.temperatura_lead || 'Morno'
};

return {
  json: {
    ...payload,
    resposta_cliente: d.resposta_cliente || null,
    insight_rapido: d.insight_rapido || null,
    conversa_original: mergeNode.conversa
  }
};
